export function getReviewI18n(slug: string, lang: string): CardReviewI18n | undefined {
  if (lang === 'fr') return undefined; // FR content lives in cardReviews.ts
  return REVIEW_I18N[`${slug}__${lang}`] ?? undefined;
}
